import json
import time
from dataclasses import dataclass, field
from typing import Optional
from openai import OpenAI

client = OpenAI()

# ─── Data Models ──────────────────────────────────────────────────────────────

@dataclass
class Source:
    url: str
    title: str
    content: str
    domain: str = ''
    published_date: Optional[str] = None
    authority_score: float = 0.5
    relevance_score: float = 0.5

    @property
    def quality_score(self) -> float:
        freshness = 1.0  # default if no date
        if self.published_date:
            try:
                days_old = (time.time() - time.mktime(
                    time.strptime(self.published_date, '%Y-%m-%d')
                )) / 86400
                freshness = max(0.1, 1.0 - days_old / 365)
            except Exception:
                pass
        return (0.35 * self.authority_score +
                0.30 * self.relevance_score +
                0.35 * freshness)


@dataclass
class Claim:
    statement: str
    sources: list[str] = field(default_factory=list)  # source URLs
    confidence: float = 0.5
    contradicted_by: list[str] = field(default_factory=list)


@dataclass
class ResearchState:
    original_question: str
    hypothesis: str = ''
    sub_questions: list[str] = field(default_factory=list)
    answered_sub_questions: set = field(default_factory=set)
    sources: list[Source] = field(default_factory=list)
    claims: list[Claim] = field(default_factory=list)
    rounds_completed: int = 0
    confidence: float = 0.0

    def coverage(self) -> float:
        if not self.sub_questions:
            return 0.0
        return len(self.answered_sub_questions) / len(self.sub_questions)

    def add_source(self, source: Source):
        urls = {s.url for s in self.sources}
        if source.url not in urls:
            self.sources.append(source)


# ─── Simulated Search (replace with real search API) ──────────────────────────

def search_web(query: str, num_results: int = 3) -> list[Source]:
    """
    Stub — replace with Brave Search API, Serper, or Tavily.
    Returns fake sources for illustration.
    """
    return [
        Source(
            url=f'https://example.com/{i}',
            title=f'Result {i} for: {query}',
            content=f'This article discusses {query} with detailed analysis. '
                    f'Key finding {i}: relevant data point.',
            domain='example.com',
            published_date='2025-01-15',
            authority_score=0.7,
            relevance_score=0.8,
        )
        for i in range(num_results)
    ]


# ─── LLM Calls ────────────────────────────────────────────────────────────────

def llm_json(messages: list[dict], temperature: float = 0.0) -> dict:
    resp = client.chat.completions.create(
        model='gpt-4o-mini',
        messages=messages,
        response_format={'type': 'json_object'},
        temperature=temperature,
    )
    return json.loads(resp.choices[0].message.content)


def llm_text(messages: list[dict], temperature: float = 0.3) -> str:
    resp = client.chat.completions.create(
        model='gpt-4o-mini',
        messages=messages,
        temperature=temperature,
    )
    return resp.choices[0].message.content


# ─── Research Agent ───────────────────────────────────────────────────────────

class AutonomousResearchAgent:
    def __init__(self, max_rounds: int = 4, confidence_threshold: float = 0.80):
        self.max_rounds = max_rounds
        self.confidence_threshold = confidence_threshold

    def research(self, question: str) -> dict:
        state = ResearchState(original_question=question)

        # Phase 1: Plan
        self._form_hypothesis_and_plan(state)
        print(f'Hypothesis: {state.hypothesis}')
        print(f'Sub-questions ({len(state.sub_questions)}): '
              + ', '.join(state.sub_questions[:3]))

        # Phase 2: Iterative evidence collection
        for round_num in range(self.max_rounds):
            state.rounds_completed = round_num + 1
            print(f'\n--- Round {state.rounds_completed} | confidence={state.confidence:.2f} ---')

            queries = self._generate_queries(state)
            for q in queries:
                sources = search_web(q)
                for s in sources:
                    state.add_source(s)

            self._extract_claims(state)
            self._detect_answered_sub_questions(state)
            self._detect_contradictions(state)
            state.confidence = self._compute_confidence(state)

            print(f'Sources: {len(state.sources)} | '
                  f'Claims: {len(state.claims)} | '
                  f'Coverage: {state.coverage():.0%}')

            if state.confidence >= self.confidence_threshold:
                print('Confidence threshold reached — stopping early.')
                break

        # Phase 3: Synthesise
        report = self._synthesize(state)
        return {
            'question': question,
            'confidence': state.confidence,
            'rounds': state.rounds_completed,
            'sources_used': len(state.sources),
            'report': report,
        }

    # ── Planning ──────────────────────────────────────────────────────────────

    def _form_hypothesis_and_plan(self, state: ResearchState):
        result = llm_json([
            {'role': 'system', 'content': (
                'You are a research planner. Given a question, '
                'form an initial hypothesis and break it into 3-5 specific '
                'sub-questions that together would fully answer it. '
                'Return JSON: {"hypothesis": str, "sub_questions": [str]}'
            )},
            {'role': 'user', 'content': state.original_question},
        ])
        state.hypothesis = result.get('hypothesis', '')
        state.sub_questions = result.get('sub_questions', [])

    # ── Query Generation ──────────────────────────────────────────────────────

    def _generate_queries(self, state: ResearchState) -> list[str]:
        unanswered = [
            q for q in state.sub_questions
            if q not in state.answered_sub_questions
        ]
        if not unanswered:
            return [state.original_question]  # fallback

        result = llm_json([
            {'role': 'system', 'content': (
                'Generate 2-3 web search queries to answer the given sub-questions. '
                'Queries should be specific and avoid repeating prior searches. '
                'Return JSON: {"queries": [str]}'
            )},
            {'role': 'user', 'content': json.dumps({
                'sub_questions': unanswered[:3],
                'hypothesis': state.hypothesis,
                'round': state.rounds_completed,
            })},
        ])
        return result.get('queries', [state.original_question])

    # ── Evidence Processing ───────────────────────────────────────────────────

    def _extract_claims(self, state: ResearchState):
        if not state.sources:
            return

        # Use top-quality sources to limit tokens
        top_sources = sorted(
            state.sources, key=lambda s: s.quality_score, reverse=True
        )[:6]
        source_text = '\n\n'.join(
            f'[{s.url}]\n{s.content[:400]}' for s in top_sources
        )

        result = llm_json([
            {'role': 'system', 'content': (
                'Extract factual claims from the sources. '
                'For each claim include the source URL. '
                'Return JSON: {"claims": [{"statement": str, "source_url": str, "confidence": float}]}'
            )},
            {'role': 'user', 'content': source_text},
        ])

        existing_statements = {c.statement for c in state.claims}
        for c in result.get('claims', []):
            if c['statement'] not in existing_statements:
                state.claims.append(Claim(
                    statement=c['statement'],
                    sources=[c.get('source_url', '')],
                    confidence=c.get('confidence', 0.5),
                ))

    def _detect_answered_sub_questions(self, state: ResearchState):
        if not state.claims:
            return
        claims_text = '\n'.join(c.statement for c in state.claims[:20])
        result = llm_json([
            {'role': 'system', 'content': (
                'Given the claims and sub-questions, identify which sub-questions '
                'are now sufficiently answered by the evidence. '
                'Return JSON: {"answered": [str]} — only include sub-questions that have evidence.'
            )},
            {'role': 'user', 'content': json.dumps({
                'sub_questions': state.sub_questions,
                'claims_summary': claims_text,
            })},
        ])
        for q in result.get('answered', []):
            state.answered_sub_questions.add(q)

    def _detect_contradictions(self, state: ResearchState):
        if len(state.claims) < 2:
            return
        claims_text = '\n'.join(
            f'{i}. {c.statement}' for i, c in enumerate(state.claims[:15])
        )
        result = llm_json([
            {'role': 'system', 'content': (
                'Identify contradictory claims in the list. '
                'Return JSON: {"contradictions": [{"claim_a": str, "claim_b": str, "resolution": str}]}'
            )},
            {'role': 'user', 'content': claims_text},
        ])
        # Flag contradicted claims (simplified)
        for contradiction in result.get('contradictions', []):
            for claim in state.claims:
                if claim.statement in (
                    contradiction.get('claim_a', ''),
                    contradiction.get('claim_b', ''),
                ):
                    claim.contradicted_by.append(contradiction.get('resolution', 'contradicted'))

    def _compute_confidence(self, state: ResearchState) -> float:
        coverage = state.coverage()
        if not state.claims:
            return 0.0
        uncontradicted = sum(
            1 for c in state.claims if not c.contradicted_by
        ) / len(state.claims)
        source_quality = sum(
            s.quality_score for s in state.sources
        ) / max(len(state.sources), 1)
        return min(1.0, 0.4 * coverage + 0.35 * uncontradicted + 0.25 * source_quality)

    # ── Synthesis ─────────────────────────────────────────────────────────────

    def _synthesize(self, state: ResearchState) -> str:
        top_claims = sorted(
            state.claims,
            key=lambda c: c.confidence - 0.5 * len(c.contradicted_by),
            reverse=True
        )[:10]
        claims_text = '\n'.join(
            f'- {c.statement} [confidence={c.confidence:.1f}'
            + (f', contradicted: {c.contradicted_by[0][:50]}' if c.contradicted_by else '')
            + ']'
            for c in top_claims
        )
        source_list = '\n'.join(
            f'- {s.url} (quality={s.quality_score:.2f})'
            for s in sorted(state.sources, key=lambda x: x.quality_score, reverse=True)[:5]
        )
        return llm_text([
            {'role': 'system', 'content': (
                'You are a research writer. Synthesize the claims into a clear, '
                'factual answer to the original question. '
                'Cite sources inline as [source_url]. '
                'If contradictions exist, present multiple perspectives. '
                'End with a "Confidence" section stating overall research confidence.'
            )},
            {'role': 'user', 'content': (
                f'Question: {state.original_question}\n\n'
                f'Claims:\n{claims_text}\n\n'
                f'Top Sources:\n{source_list}'
            )},
        ])


# ─── Demo ─────────────────────────────────────────────────────────────────────

if __name__ == '__main__':
    agent = AutonomousResearchAgent(max_rounds=3, confidence_threshold=0.75)
    result = agent.research(
        'What are the production trade-offs of using Apache Kafka vs RabbitMQ '
        'for high-throughput event streaming in 2025?'
    )
    print('\n=== FINAL REPORT ===')
    print(result['report'])
    print(f'\nConfidence: {result["confidence"]:.0%} | '
          f'Rounds: {result["rounds"]} | Sources: {result["sources_used"]}')
